INSERT INTO LOCATION (Location_ID, State, County, Nearest_Town, Nearest_Road, Location_Details, A_G_Reference) VALUES (11, 'California', 'Del Norte', 'Hiouchi is not really a town,so Crescent City woul', 'HWY.199/Redwood Hwy.', 'There  is a small concrete bridge just off Hwy 199 at Hiouchi which is between the Oregon Tunnel and Crescent City,CA. If you are travelling north on 199 going towards Oregon the bridge and road would be to your right.This paved road goes for many miles south of the Hwy. I heard some people refer to this road as the road which was supposed to have been made into a super highway.I think they were just putting me on about that.', NULL);
