INSERT INTO LOCATION (Location_ID, State, County, Nearest_Town, Nearest_Road, Location_Details, A_G_Reference) VALUES (17, 'Colorado', 'Alamosa', 'Blanca, Colorado 81123', 'Colorado Highway 150', 'From I-25 at Walsenberg, take U.S. 160 westbound. Turn right on Co. 150. Go about 2 miles and turn on what is called Lake Como Road. This is the toughest Four Wheel Drive Road in Colorado, and the third toughest in the U.S. You take the road untill it ends at a lake, that is 6.8 miles. It will take you about4 hours.', NULL);
